sp_rectangle_menu_item.record_script:
var bannerAwaitingAssignment = function(data){
  var u = gs.getUser().getID();

  //------------------------------------------------------------------------------------------------------------------
  // Build the Filter using Task Manger OUs, OUs where member and GTA if they are in that role
  // Get the list of OUs where the current user is a Task Manager
  var primary_assigneeFilter = "primary_assigneeIN";
  var taskSystemSettings = new tasking_System_Settings_Scripts();
  primary_assigneeFilter += taskSystemSettings.getMyOUTaskManagers(u).join(",");
  // Get the list of OUs where the current user is a Member
  var primary_assigneeMemberFilter = "primary_assigneeIN";
  primary_assigneeMemberFilter +=   taskSystemSettings.getOUsWhereUserIsAMember(u).join(",");

  var filter = 'stateIN-5,11^' + primary_assigneeFilter;
  var filterMember = 'stateIN-5,11^' + primary_assigneeMemberFilter + '^primary_assignee.tasking_authoritiesISEMPTY';
  filter = filter + '^NQ' + filterMember;
  var isGTA = gs.getUser().hasRole("x_153465_discovert.tasker_global_Tasking_Authority_member_admin");
  if(isGTA){
    var filterGTA = 'stateIN-5,11^primary_assigneeISNOTEMPTY^primary_assignee.tasking_authoritiesISEMPTY';
    filter = filter + '^NQ' + filterGTA;
  }

  var tbf = new TaskerBannerFilters();

  tbf.label = 'Awaiting Assignment';
  tbf.table = 'x_153465_discovert_route_task_instance';
  tbf.filter = filter;
  tbf.orderDesc = 'sys_updated_on';
  tbf.idField = 'sys_id';
  tbf.displayFieldName = 'task_name';
  tbf.linkView = 'sp';
  tbf.pageId = 'discovertasker_taskdetails';
  tbf.viewAllLinkTitle = gs.getMessage('View all requests');
  tbf.viewAllLinkPageId = 'discovertasker_detailsdrilldown';

  tbf.viewAllLinkView = 'Unassigned';
  if(isGTA){
    tbf.viewAllLinkFilter = 'stateIN-5,11%5E' + primary_assigneeFilter + '%5ENQstateIN-5,11%5E' + primary_assigneeMemberFilter + '%5Eprimary_assignee.tasking_authoritiesISEMPTY%5ENQstateIN-5,11%5Eprimary_assigneeISNOTEMPTY%5Eprimary_assignee.tasking_authoritiesISEMPTY';
  }else{
    tbf.viewAllLinkFilter = 'stateIN-5,11%5E' + primary_assigneeFilter + '%5ENQstateIN-5,11%5E' + primary_assigneeMemberFilter + '%5Eprimary_assignee.tasking_authoritiesISEMPTY';
  }

  tbf.createBanner();
  data.items = tbf.items;
  data.record_watchers = tbf.record_watchers;
  data.count = tbf.count;
}

bannerAwaitingAssignment(data);
